                <AddAwardForm 
                    tournamentId={tournament.id} 
                    players={players} 
                    onSuccess={() => { setIsAdding(false); setAwards(getAwardsByTournament(tournament.id)); }} 
                    onCancel={() => setIsAdding(false)} 
                    addTournamentAward={addTournamentAward}
                />
            )}
        </FormModal>
    );
};

